from flask import Flask, jsonify, request, send_from_directory
from flask_cors import CORS
from flask_jwt_extended import JWTManager, create_access_token, jwt_required, get_jwt_identity
import pickle
import os
from datetime import datetime, timedelta
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__, static_folder="../frontend")
app.config['SECRET_KEY'] = 'your-secret-key-change-in-production'
app.config['JWT_SECRET_KEY'] = 'jwt-secret-key-change-in-production'
app.config['JWT_ACCESS_TOKEN_EXPIRES'] = timedelta(hours=24)

# Initialize extensions
CORS(app)
jwt = JWTManager(app)

# Load ML model
try:
    model_path = os.path.join(os.path.dirname(__file__), "../ml/load_model.pkl")
    model = pickle.load(open(model_path, 'rb'))
    print("ML model loaded successfully")
except Exception as e:
    print(f"Error loading model: {e}")
    model = None

# Simple in-memory storage (replace with MongoDB in production))\nusers = {\n    'admin': {\n        'id': '1',\n        'username': 'admin',\n        'email': 'admin@cloudload.com',\n        'password_hash': generate_password_hash('admin123'),\n        'role': 'admin'\n    }\n}\n\npredictions = []\n\n# Scaling decision function\ndef scale_decision(predicted_load):\n    if predicted_load > 75:\n        return \"SCALE UP\"\n    elif predicted_load < 40:\n        return \"SCALE DOWN\"\n    else:\n        return \"NO ACTION\"\n\ndef get_scaling_recommendations(predicted_load, confidence):\n    recommendations = []\n    \n    if predicted_load > 85:\n        recommendations.append({\n            'priority': 'HIGH',\n            'action': 'Immediate scale up required',\n            'reason': 'CPU load exceeds 85% - performance degradation likely',\n            'suggested_instances': 'increase by 50%'\n        })\n    elif predicted_load > 75:\n        recommendations.append({\n            'priority': 'MEDIUM',\n            'action': 'Scale up recommended',\n            'reason': 'CPU load above optimal threshold',\n            'suggested_instances': 'increase by 25%'\n        })\n    elif predicted_load < 30:\n        recommendations.append({\n            'priority': 'LOW',\n            'action': 'Consider scaling down',\n            'reason': 'Low CPU utilization - cost optimization opportunity',\n            'suggested_instances': 'decrease by 25%'\n        })\n    else:\n        recommendations.append({\n            'priority': 'INFO',\n            'action': 'Current capacity is optimal',\n            'reason': 'CPU load within acceptable range',\n            'suggested_instances': 'maintain current'\n        })\n    \n    if confidence < 0.7:\n        recommendations.append({\n            'priority': 'WARNING',\n            'action': 'Monitor closely',\n            'reason': f'Prediction confidence is {confidence:.1%} - consider manual verification',\n            'suggested_instances': 'review required'\n        })\n    \n    return recommendations\n\n# Routes\n@app.route(\"/\")\ndef home():\n    return send_from_directory(app.static_folder, \"index.html\")\n\n# Authentication Routes\n@app.route(\"/api/auth/login\", methods=[\"POST\"])\ndef login():\n    data = request.get_json()\n    \n    if not data or not all(k in data for k in ('username', 'password')):\n        return jsonify({'message': 'Missing username or password'}), 400\n    \n    user = users.get(data['username'])\n    \n    if user and check_password_hash(user['password_hash'], data['password']):\n        access_token = create_access_token(identity=user['id'])\n        \n        return jsonify({\n            'access_token': access_token,\n            'user': {\n                'id': user['id'],\n                'username': user['username'],\n                'email': user['email'],\n                'role': user['role']\n            }\n        }), 200\n    else:\n        return jsonify({'message': 'Invalid credentials'}), 401\n\n@app.route(\"/api/auth/register\", methods=[\"POST\"])\ndef register():\n    data = request.get_json()\n    \n    if not data or not all(k in data for k in ('username', 'email', 'password')):\n        return jsonify({'message': 'Missing required fields'}), 400\n    \n    if data['username'] in users:\n        return jsonify({'message': 'Username already exists'}), 409\n    \n    user_id = str(len(users) + 1)\n    users[data['username']] = {\n        'id': user_id,\n        'username': data['username'],\n        'email': data['email'],\n        'password_hash': generate_password_hash(data['password']),\n        'role': 'user'\n    }\n    \n    return jsonify({\n        'message': 'User created successfully',\n        'user_id': user_id\n    }), 201\n\n# Prediction Routes\n@app.route(\"/api/predict/<int:time>\", methods=[\"GET\"])\n@jwt_required()\ndef predict(time):\n    if not model:\n        return jsonify({'message': 'ML model not available'}), 503\n    \n    try:\n        # Make prediction\n        predicted_load = model.predict([[time]])[0]\n        confidence = 0.85  # Simplified confidence score\n        \n        # Get scaling decision\n        action = scale_decision(predicted_load)\n        recommendations = get_scaling_recommendations(predicted_load, confidence)\n        \n        # Save prediction\n        prediction_data = {\n            'time_slot': time,\n            'predicted_load': round(predicted_load, 2),\n            'confidence': confidence,\n            'action': action,\n            'timestamp': datetime.utcnow().isoformat(),\n            'user_id': get_jwt_identity()\n        }\n        predictions.append(prediction_data)\n        \n        return jsonify({\n            'time_slot': time,\n            'predicted_cpu_load': round(predicted_load, 2),\n            'confidence': confidence,\n            'action': action,\n            'recommendations': recommendations,\n            'model_info': 'random_forest',\n            'timestamp': prediction_data['timestamp']\n        }), 200\n        \n    except Exception as e:\n        return jsonify({'message': f'Prediction error: {str(e)}'}), 500\n\n@app.route(\"/api/predict/batch\", methods=[\"POST\"])\n@jwt_required()\ndef batch_predict():\n    if not model:\n        return jsonify({'message': 'ML model not available'}), 503\n    \n    data = request.get_json()\n    \n    if not data or 'time_slots' not in data:\n        return jsonify({'message': 'Missing time_slots array'}), 400\n    \n    time_slots = data['time_slots']\n    if len(time_slots) > 24:\n        return jsonify({'message': 'Maximum 24 time slots allowed'}), 400\n    \n    try:\n        batch_predictions = []\n        for time_slot in time_slots:\n            predicted_load = model.predict([[time_slot]])[0]\n            confidence = 0.85\n            action = scale_decision(predicted_load)\n            \n            batch_predictions.append({\n                'time_slot': time_slot,\n                'predicted_load': round(predicted_load, 2),\n                'confidence': confidence,\n                'action': action,\n                'model_used': 'random_forest',\n                'recommendations': get_scaling_recommendations(predicted_load, confidence)\n            })\n        \n        return jsonify({'predictions': batch_predictions}), 200\n        \n    except Exception as e:\n        return jsonify({'message': f'Batch prediction error: {str(e)}'}), 500\n\n# Analytics Routes\n@app.route(\"/api/analytics/dashboard\", methods=[\"GET\"])\n@jwt_required()\ndef dashboard_analytics():\n    user_id = get_jwt_identity()\n    user_predictions = [p for p in predictions if p.get('user_id') == user_id]\n    \n    return jsonify({\n        'user_predictions': user_predictions[-20:],  # Last 20 predictions\n        'user_info': {\n            'total_predictions': len(user_predictions)\n        }\n    }), 200\n\n# Health Check\n@app.route(\"/api/health\", methods=[\"GET\"])\ndef health_check():\n    return jsonify({\n        'status': 'healthy',\n        'timestamp': datetime.utcnow().isoformat(),\n        'version': '1.0.0',\n        'model_loaded': model is not None\n    }), 200\n\n# Error Handlers\n@app.errorhandler(404)\ndef not_found(error):\n    return jsonify({'message': 'Endpoint not found'}), 404\n\n@app.errorhandler(500)\ndef internal_error(error):\n    return jsonify({'message': 'Internal server error'}), 500\n\nif __name__ == \"__main__\":\n    print(\"Starting AI Cloud Load Management Backend...\")\n    print(\"Default admin credentials: admin / admin123\")\n    app.run(debug=True, host='0.0.0.0', port=5000)